/**
 * Hand-curated long-form intros for the highest-traffic passport pages.
 * These ship as primary SEO content — Google rewards genuinely useful prose,
 * and a 40k-page site templated identically reads as thin content.
 *
 * For passports without a curated intro we fall back to a generated paragraph
 * driven by the live coverage data (see passportIntroFallback in
 * src/app/passport/[iso]/page.tsx).
 *
 * Each intro is intentionally factual, current as of 2024–2025, and avoids
 * promising any specific outcome — the disclaimer language in /disclaimer
 * does the legal work; this is the user-helpful narrative.
 */
export const PASSPORT_INTROS: Record<string, string> = {
  US: `The United States passport ranks among the most travel-friendly in the world. US citizens enter most of Europe (Schengen Area), the United Kingdom, Japan, South Korea, Singapore, Australia (with eTA), Canada (with eTA) and most of Latin America without a visa for short stays — typically 30 to 90 days. For longer stays, most countries require an embassy-issued visa. US passport holders are also eligible for many countries' digital-nomad and retirement visa schemes. Note that US citizens applying for visas abroad pay reciprocity fees in many countries; we surface those fee components on each individual route page.`,

  GB: `The United Kingdom passport offers wide visa-free or eTA-only access across the European Union, the United States (ESTA), Canada (eTA), Australia (eVisitor / ETA), Japan, Singapore, and most of South America. Following Brexit, UK citizens lost automatic EU residence rights but retained 90-days-in-180 visa-free travel under the Schengen short-stay regime. From 2026, UK travellers will need ETIAS authorisation for Schengen entry. Long-stay options include Spain's digital-nomad visa, Portugal's D7, France's long-stay visitor visa, and various skilled-worker routes — covered on each destination page.`,

  DE: `The German passport is one of the strongest globally, granting visa-free or eTA-only access to over 180 countries. As an EU member, Germany offers freedom of movement throughout the European Union and EEA, as well as Schengen short-stay access. German citizens travel visa-free to the United States (ESTA), Canada (eTA), Australia (eVisitor), Japan, South Korea, the UAE, and most of Latin America and Southeast Asia. Notable destinations requiring an embassy visa or e-Visa include Russia, China (some routes; Hong Kong / Macau are visa-free), Vietnam (e-Visa), and Saudi Arabia (e-Visa).`,

  CA: `The Canadian passport provides visa-free or eTA-only entry to most major destinations including the European Union (Schengen — 90 days), the United Kingdom, Japan, South Korea, Australia (eVisitor), Singapore, and most of the Americas. Canadians travelling to the United States are exempt from ESTA but still require I-94 entry. Long-stay options vary widely: Australian working holiday visas are available to Canadians under 35; Schengen long-stay national visas (D-class) are issued by individual EU member states; and bilateral working-holiday agreements exist with Japan, South Korea, Ireland, and several others.`,

  AU: `The Australian passport offers strong visa-free access including the European Union (Schengen — 90 days), the United Kingdom (with ETA from 2025), the United States (ESTA), Canada (eTA), Japan, South Korea, and most of Southeast Asia. Australians benefit from working-holiday agreements with the UK, Ireland, Canada, France, Germany, and many other countries — typically allowing 12 to 24 months of work and travel. For permanent migration, most destinations require employer sponsorship or a points-based skilled-worker route; Canada's Express Entry and the UK's Skilled Worker route are common pathways.`,

  IN: `The Indian passport requires advance visa or e-Visa for many destinations. Visa-free or visa-on-arrival countries include Bhutan, Nepal, the Maldives, Mauritius, Indonesia, Thailand (limited), and several Caribbean nations. Most major destinations — the United States, United Kingdom, Schengen Area, Canada, Australia — require an embassy-issued visa. Indian passport holders are heavily represented in the Skilled Worker pipelines for the UK, Canada (Express Entry), and Australia (Subclass 482), and in the United States H-1B program. Student visa volumes to the UK (Tier 4 / Student route), Australia (Subclass 500), Canada, and the US are among the highest globally.`,

  CN: `The Chinese passport requires advance visa for most major Western destinations including the United States, United Kingdom, Schengen, Canada, and Australia. Notable visa-free or visa-on-arrival access includes much of Southeast Asia (Singapore, Thailand, Malaysia for short stays), the Maldives, the UAE, and several countries in the Americas. China's bilateral mutual-visa-exemption agreements have expanded substantially in 2024–2025 — Thailand, Singapore and several European countries now have reciprocal visa-free arrangements. Long-stay routes typically require embassy applications with documents authenticated through China's foreign-affairs ministry.`,

  JP: `The Japanese passport consistently ranks at the top of global mobility indexes, with visa-free or eTA-only access to nearly 190 countries. Japanese citizens travel visa-free to the United States (ESTA), Canada (eTA), Australia (eVisitor), the UK, Schengen Area, and most of Asia and Latin America. For long stays, working-holiday agreements exist with Australia, New Zealand, Canada, the UK, Germany, France, South Korea, and many others. Japanese citizens are also eligible for the US E-2 treaty-investor visa and various professional-class routes globally.`,

  BR: `The Brazilian passport offers visa-free entry to the European Union (Schengen — 90 days), the UK, Japan, and most of Latin America under Mercosur agreements. Brazilians require visas for the United States (B1/B2), Canada, and Australia. Mercosur residency agreements grant Brazilian citizens streamlined residence rights in Argentina, Uruguay, Paraguay, Chile, Bolivia, Colombia, Ecuador, and Peru. Portugal in particular maintains close ties — Brazilians can access D7 (passive income) and digital-nomad routes with simplified document recognition under the CPLP framework.`,

  KR: `The South Korean passport is one of the strongest in the world, providing visa-free or eTA-only entry to nearly 190 destinations including the United States (ESTA), Canada (eTA), the European Union, the United Kingdom, Australia (eVisitor), Japan, and most of Southeast Asia. Working-holiday agreements with Australia, New Zealand, Canada, Ireland, the UK, Germany, France, and several other countries make multi-year travel-and-work options widely available. For permanent migration, employer-sponsored skilled-worker routes (UK Skilled Worker, Canada Express Entry, Australia Subclass 482) are common.`,

  IT: `The Italian passport offers freedom of movement throughout the European Union and EEA, plus visa-free or eTA-only access to the United States (ESTA), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America and Southeast Asia. Italian citizens are uniquely well-positioned for long-stay options through ius sanguinis citizenship recognition, which simplifies family reunification with descendants of Italian emigrants worldwide. Bilateral working-holiday agreements exist with Australia, New Zealand, Canada, Japan, and South Korea.`,

  ES: `The Spanish passport grants EU/EEA freedom of movement plus broad visa-free or eTA-only access to the Americas, the United States (ESTA), Canada (eTA), the UK, Japan, Australia (eVisitor), and most of Asia. Spanish citizens benefit from preferential pathways to several Latin American countries — including streamlined residency in Argentina, Mexico, Chile and Uruguay through bilateral conventions — and from the Iberoamerican naturalization framework. For long-stay outside the EU, the United States E-2 treaty-investor visa is available to Spanish nationals.`,

  NL: `The Dutch passport provides visa-free or eTA-only entry to the entire European Union, the United States (ESTA), Canada (eTA), the UK, Japan, Australia (eVisitor), and most of Latin America and Southeast Asia. The Netherlands is part of the Schengen Area, granting Dutch citizens 90-day visa-free travel across all member states. Bilateral working-holiday agreements with Australia, New Zealand, Canada, Japan, and South Korea provide multi-year work-and-travel options. For permanent migration, the United States offers the E-1 / E-2 treaty-investor and trader categories to Dutch nationals.`,

  RU: `The Russian passport requires visas for many major Western destinations including the United States, the European Union (suspended visa-facilitation since 2022), Canada, the UK, and Australia. Visa-free or visa-on-arrival access remains broad across Latin America, the post-Soviet space, and parts of Asia and Africa. Long-stay options for Russian nationals have narrowed significantly since 2022 — many EU member states have suspended Russian Golden Visa and investor-residence schemes. The UAE, Turkey, Serbia, Georgia, Armenia, and Thailand remain accessible for both short and long-stay residence.`,

  SG: `The Singaporean passport is consistently ranked at the very top of global mobility indexes, with visa-free or eTA-only access to nearly 195 countries. Singaporean citizens enter the United States (ESTA), Canada (eTA), the European Union, the United Kingdom, Australia (ETA), Japan, and South Korea visa-free for short stays. Working-holiday agreements with Australia, New Zealand, Germany, the UK, and several other countries are widely used. Singapore's reciprocal short-stay arrangements within ASEAN provide visa-free entry across Southeast Asia.`,

  AE: `The UAE passport has risen rapidly in global mobility rankings over the past decade, offering visa-free or eTA-only access to over 180 countries. Emirati citizens enter the European Union (Schengen — 90 days, with ETIAS from 2026), the UK (ETA), and most of Asia, Latin America, and Africa visa-free. UAE passport holders benefit from GCC reciprocity for free residence and work across Saudi Arabia, Kuwait, Bahrain, Qatar, and Oman. Long-stay options outside the GCC commonly use embassy-issued visas with bilateral fee waivers.`,

  CH: `The Swiss passport grants Schengen Area free movement, EU labour-market access under bilateral agreements, and visa-free or eTA-only entry to the United States (ESTA), Canada (eTA), the UK, Japan, Australia (eVisitor), and most of Latin America and Southeast Asia. Swiss citizens are eligible for the US E-2 treaty-investor visa, the UK's ETA, and most working-holiday programmes. For non-EU long-stay routes, Switzerland is a popular originating country for the Spain Digital Nomad and Portugal D7 visa programmes.`,

  SE: `The Swedish passport offers EU/EEA free movement, Schengen Area access, and visa-free or eTA-only entry to the United States (ESTA), Canada (eTA), the United Kingdom, Australia (eVisitor), Japan, South Korea, and most of Latin America and Southeast Asia. Working-holiday agreements with Australia, New Zealand, Canada, Japan, and South Korea provide popular gap-year and post-graduate options. Sweden's strong tax-treaty network supports a wide range of long-stay employment-based migrations through E-2 (US), Express Entry (Canada), and EU Blue Card pathways.`,

  BE: `The Belgian passport offers EU/EEA free movement, Schengen Area access, and visa-free or eTA-only entry to ~190 destinations including the United States (ESTA), Canada (eTA), the UK (ETA from 2025), Japan, South Korea, Australia (eVisitor), the UAE, and most of Latin America + Southeast Asia. Brussels-based Belgians have privileged access to EU institutional employment + NATO HQ (Brussels) + SHAPE (Mons) postings. Working-holiday agreements with Australia, NZ, Canada, Japan, Korea, Taiwan, Hong Kong, Argentina, Chile. Multilingual Belgian education (Dutch / French / German) supports mobility across all three language zones in Europe + Francophone Africa (DR Congo / Burundi / Rwanda historical ties).`,

  PL: `The Polish passport offers EU/EEA free movement, Schengen Area access (since 2007), and visa-free or eTA-only entry to ~185 destinations including the United States (ESTA — joined Visa Waiver Program in November 2019), Canada (eTA), the UK (ETA from 2025), Japan, South Korea, Australia (eVisitor), the UAE, and most of Latin America + Southeast Asia. Working-holiday agreements with Australia, NZ, Canada, Japan, Korea, Taiwan. Polish diaspora extensive — UK ~700k, Germany ~2M, US ~9M descent (Chicago especially), Ireland ~120k, Netherlands. Polish students + workers utilise Erasmus+ + EURES mobility extensively. Belarus + Ukraine + Russia mobility (visa-required since 2022) historically dense.`,

  ZA: `The South African passport requires visas for many major Western destinations including the United States, Canada, Australia, and most of the European Union (Schengen — Annex I), but offers visa-free or visa-on-arrival access to the United Kingdom (90 days), most of Africa under SADC and ECOWAS arrangements, and parts of Latin America and Southeast Asia. South African passport holders are heavily represented in UK Skilled Worker, Canada Express Entry, and Australia Subclass 482 employer-sponsored migration. Bilateral working-holiday agreements include Australia, New Zealand, Canada, and Ireland.`,

  TR: `The Turkish passport offers visa-free or eTA-only access to most of the Balkans, Latin America, and parts of Africa and Asia, but requires Schengen visas for EU travel and ESTA for US travel. Turkey's recent bilateral agreements have expanded mutual-visa-exemption arrangements with Russia, Ukraine, Azerbaijan, Singapore, and several Latin American countries. Long-stay routes for Turkish nationals into the EU commonly use the EU Blue Card (Germany), Spain Digital Nomad, Portugal D7, and the UK Skilled Worker route.`,

  IE: `The Irish passport grants EU/EEA freedom of movement, full UK Common Travel Area rights (Ireland and the UK retain a special arrangement separate from Schengen), and visa-free or eTA-only access to the United States (ESTA), Canada (eTA), Australia (eVisitor), Japan, and most of Latin America and Southeast Asia. Irish citizens benefit from the US E-3 treaty-trader visa equivalent (J-1 graduate), bilateral working-holiday programmes with Australia, New Zealand, Canada, Japan, and South Korea, and J-1 internships in the United States.`,

  MX: `The Mexican passport offers visa-free or eTA-only access to the European Union (Schengen — 90 days), the United Kingdom, Japan, South Korea, and most of Latin America. Mexicans require visas for the United States (B1/B2), Canada (after 2016 reimposed eTA-with-conditions), and Australia. Mexico's bilateral working-holiday agreements include Canada, France, Germany, New Zealand, South Korea, and Japan. Long-stay routes commonly use Canada Express Entry, Spain Digital Nomad, and Portugal D7 — all open to Mexican applicants.`,

  NZ: `The New Zealand passport ranks in the global top tier, with visa-free or eTA-only entry to ~190 destinations including Schengen (ETIAS from late 2026), the UK (ETA), the US (ESTA), Canada (eTA), Japan, South Korea, and Australia (under the Trans-Tasman Travel Arrangement, which grants indefinite work and residence rights). Kiwis qualify for working-holiday agreements with the UK, Ireland, Canada, Germany, France, Japan, and South Korea. New Zealand's bilateral Investor and Skilled Migrant Category routes (rebuilt under SMC 2024) attract reciprocal interest from Canada and Australia.`,

  AT: `The Austrian passport grants EU freedom of movement, full Schengen Area access, and visa-free or eTA-only entry to the US (ESTA), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America and Southeast Asia. Austrians are eligible for the US E-2 treaty-investor visa and working-holiday agreements with Australia, New Zealand, Canada, Japan, South Korea, and Taiwan. From October 2025 the EU Entry/Exit System (EES) records all Schengen entries biometrically, including outbound trips by Austrian residents — though no visa changes apply for Austrian citizens.`,

  FI: `The Finnish passport offers EU/EEA free movement, Schengen access, and visa-free or eTA-only entry to the US (ESTA), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America and Southeast Asia. Finland's Nordic Passport Union grants Finns the right to work and live in Denmark, Iceland, Norway and Sweden without permits. Working-holiday agreements include Australia, New Zealand, Canada, Japan, South Korea, and Argentina. Finnish citizens face no friction at the EU level but should note Russian border crossings remain suspended since 2023.`,

  NO: `Norway is outside the EU but inside the EEA single market — Norwegians work and reside across the EU 27 on the same terms as EU citizens, including in Switzerland through the EFTA agreements. Short-stay mobility includes ESTA entry to the US, eTA entry to Canada, ETA to the UK, eVisitor to Australia, plus K-ETA Korea and visa-free Japan. The Svalbard Treaty admits the world's nationalities to the archipelago without visa — a quirk relevant to nobody else. Working-holiday agreements span Argentina, Australia, Canada, Chile, Japan, South Korea and New Zealand; the 1928 Treaty of Friendship grants US E-2 treaty-investor eligibility.`,

  DK: `The Danish passport grants EU freedom of movement, full Schengen access, and visa-free or eTA-only entry to the US (ESTA), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America and Southeast Asia. Danes benefit from the Nordic Passport Union — free movement to live and work in Finland, Iceland, Norway and Sweden — and from Denmark's opt-outs on EU asylum and home-affairs cooperation (which do not affect Danish citizens' mobility). Working-holiday agreements include Australia, New Zealand, Canada, Chile, Japan, and South Korea.`,

  CZ: `The Czech passport provides EU/EEA free movement, full Schengen access, and visa-free or eTA-only entry to the US (ESTA, granted under the Visa Waiver Program in 2008), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America. Working-holiday agreements include Australia, New Zealand, Canada, Japan, South Korea, Taiwan, and Chile. Czech nationals are eligible for the US E-1/E-2 treaty-investor visas and use Germany's EU Blue Card, the UK Skilled Worker, and Canada Express Entry as common long-stay pathways outside the EU.`,

  GR: `The Greek passport grants EU freedom of movement, Schengen access, and visa-free or eTA-only entry to the US (ESTA), Canada (eTA), the UK, Japan, Australia (eVisitor), South Korea, and most of Latin America. Greeks qualify for the US E-2 treaty-investor visa under the 1954 US-Greece Treaty of Friendship. Working-holiday agreements include Australia, New Zealand, Canada, and Argentina. The Greek diaspora — large in the US, Australia, Canada, and Germany — supports widely-used family reunification and citizenship-by-descent pathways for the next generation.`,

  HU: `The Hungarian passport provides EU/EEA free movement, full Schengen access, and visa-free or eTA-only entry to the US (ESTA, since 2008), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America. Working-holiday agreements include Australia, New Zealand, Canada, Japan, South Korea, Taiwan, Argentina, and Chile. Hungarians are eligible for the US E-2 treaty-investor visa. The Hungarian-descent simplified naturalisation programme has, since 2011, materially expanded the citizenry — relevant to families with grandparents born in the historical Kingdom of Hungary.`,

  RO: `The Romanian passport grants EU/EEA free movement and — since January 2025 — full Schengen Area access (land borders, after air/sea opened March 2024). Romanians enter the US visa-free under ESTA (granted in 2025), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America. Working-holiday agreements include Australia, Canada, Japan, South Korea, and Argentina. Romania is also a popular issuing country for citizenship-by-descent pathways for ethnic Romanians from Moldova, Ukraine, and the historical Romanian-speaking diaspora. Common long-stay routes outside the EU use the UK Skilled Worker, Canada Express Entry, and Germany's EU Blue Card.`,

  HR: `The Croatian passport provides EU/EEA free movement and full Schengen access (Croatia joined Schengen 2023-01-01) plus visa-free or eTA-only entry to the US (ESTA, granted in 2021), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America. Working-holiday agreements include Australia, New Zealand, Canada, Japan, and Argentina. Croatians benefit from the relatively new ESTA access — useful for short business travel — and from EU Blue Card eligibility for skilled work across Germany, France, and the Netherlands.`,

  BG: `The Bulgarian passport grants EU/EEA free movement and — since January 2025 — full Schengen Area access (land borders, after air/sea opened March 2024). Bulgarians enter Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America visa-free, but still require a B1/B2 visa for the US (Bulgaria is not in the Visa Waiver Program despite repeated lobbying). Working-holiday agreements are limited; most long-stay routes outside the EU use Canada Express Entry, Australia Subclass 482, or the UK Skilled Worker.`,

  SK: `Since the 1993 dissolution Slovakia has run its own immigration policy, but the practical mobility surface is similar to the Czech Republic: EU and Schengen freedom of movement, US Visa Waiver Program access via ESTA (admitted 2008), Canadian eTA, Korean K-ETA. Slovaks rely heavily on Austria, Germany and Hungary for cross-border labour — Bratislava is the only EU capital where a daily commute to two foreign capitals is feasible. Working-holiday corridors run to Australia, New Zealand, Canada, Japan, South Korea, Taiwan, Argentina and Chile. The Slovak-American Treaty of 1992 carried the E-2 investor route across from the Czechoslovak-US 1928 instrument.`,

  SI: `The Slovenian passport grants EU/EEA free movement, Schengen access, and visa-free or eTA-only entry to the US (ESTA), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America. Slovenes qualify for the US E-1/E-2 treaty-investor visas. Working-holiday agreements include Australia, Canada, Japan, South Korea, and Argentina. Slovenia's strong tax-treaty network supports common long-stay routes via Canada Express Entry, Germany's EU Blue Card, and Australia Subclass 482; the country also borders four Schengen states, making cross-border work routine.`,

  LT: `The Lithuanian passport provides EU/EEA free movement, full Schengen access, and visa-free or eTA-only entry to the US (ESTA, granted in 2008), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America. Working-holiday agreements include Australia, New Zealand, Canada, Japan, South Korea, and Argentina. Lithuanians are eligible for the US E-2 treaty-investor visa. Since 2022 the Lithuanian government has suspended most short-stay visa issuance to Russian and Belarusian nationals at its consulates — relevant context if you hold a second passport or travel onward to those states.`,

  LV: `The Latvian passport grants EU/EEA free movement, full Schengen access, and visa-free or eTA-only entry to the US (ESTA, granted in 2008), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America. Latvians qualify for the US E-2 treaty-investor visa. Working-holiday agreements include Australia, Canada, Japan, and South Korea. As a Baltic state with a large Russian-speaking minority, Latvia maintains separate visa rules for non-citizens (the "alien's passport"); this intro covers ordinary Latvian citizenship documents only.`,

  EE: `The Estonian passport provides EU/EEA free movement, full Schengen access, and visa-free or eTA-only entry to the US (ESTA, granted in 2008), Canada (eTA), the UK, Japan, South Korea, Australia (eVisitor), and most of Latin America. Working-holiday agreements include Australia, New Zealand, Canada, Japan, and South Korea. Estonia is best known internationally for its e-Residency programme (not citizenship) which is widely used by digital nomads — but Estonian citizens enjoy genuine EU Blue Card, US E-2 treaty-investor, and Canada Express Entry access for long-stay routes. Estonia operates an "alien's passport" for stateless residents distinct from this overview.`,

  CY: `The Cypriot passport grants EU/EEA free movement, plus visa-free or eTA-only entry to the UK (under historical Commonwealth arrangements), Canada (eTA), Japan, South Korea, Australia (eVisitor), and most of Latin America. Cyprus is not yet in the Schengen Area — Cypriots enter Schengen visa-free for 90/180 but use the slower non-Schengen lane at airport borders. The US requires a B1/B2 visa for Cypriots (Cyprus is not in the Visa Waiver Program). Cypriot citizens are eligible for US E-2 treaty-investor status and benefit from the Commonwealth working-holiday route into the UK.`,

  MT: `The Maltese passport provides EU/EEA free movement, full Schengen access, and visa-free or eTA-only entry to the US (ESTA, granted in 2008), Canada (eTA), the UK (Commonwealth privileges), Japan, South Korea, Australia (eVisitor), and most of Latin America. Maltese citizens — uniquely among EU members — also retain rights from the Commonwealth, including streamlined UK access. Malta's controversial individual-investor citizenship programme was wound down in 2024 following EU pressure; current ordinary naturalisations follow standard residence-then-citizenship rules. Working-holiday agreements include Australia, New Zealand, and Canada.`,

  LU: `The Luxembourg passport grants EU/EEA free movement, full Schengen access, and visa-free or eTA-only entry to the US (ESTA), Canada (eTA), the UK, Japan, South Korea, Singapore, Australia (eVisitor), and most of Latin America and Southeast Asia. Luxembourgers qualify for the US E-2 treaty-investor visa under the 1962 Treaty of Friendship. Working-holiday agreements include Australia, New Zealand, Canada, Japan, South Korea, and Argentina. Luxembourg's tax-treaty network and dual-citizenship-friendly law (since 2009) make it a common second-passport destination for high-income professionals; ordinary naturalisation requires five years of residence plus Luxembourgish language proficiency.`,

  IS: `Iceland's passport sits in the global top tier — small country, outsized mobility. Holders enter the US (ESTA), Canada (eTA), the UK, the Schengen Area, Japan, South Korea, and Australia (eVisitor) without prior visa, and travel freely within the EEA. The Nordic Passport Union grants Icelanders settled-resident rights in Denmark, Finland, Sweden and Norway from day one. Unique historic ties — the 1944 Treaty of Friendship grants US E-1/E-2 trader/investor eligibility — and the Hoyvík Agreement with the Faroes make Reykjavík–Tórshavn an unusually open route. Working-holiday programmes include Japan, Australia, New Zealand and Canada.`,

  TW: `The Taiwanese passport offers visa-free or eTA-only entry to ~145 destinations including the US (ESTA, granted in 2012), Canada (eTA), the UK, the Schengen Area (with ETIAS from late 2026), Japan, South Korea, Australia (eVisitor), and most of Latin America. China requires a Mainland Travel Permit (台胞证) rather than treating the Taiwan passport as foreign. Taiwanese citizens benefit from working-holiday agreements with Australia, New Zealand, Canada, Germany, France, Japan, South Korea, the UK, and Ireland. Several Latin American allies (Paraguay, Guatemala) provide additional reciprocal preferences.`,

  HK: `The Hong Kong SAR passport offers visa-free or eTA-only entry to ~170 destinations including the UK (6 months visa-free), Schengen (90/180 with ETIAS from late 2026), Japan, South Korea, Singapore, Australia (eVisitor), and most of Southeast Asia. The US requires a B1/B2 visa. Hong Kong residents emigrating to the UK under the BN(O) Visa scheme (launched January 2021) use a separate route grounded in pre-1997 nationality status. China requires a Home Return Permit rather than a Hong Kong SAR passport. Working-holiday agreements include Australia, New Zealand, Canada, Germany, France, Ireland, Japan, and South Korea.`,

  IL: `The Israeli passport ranks high globally with visa-free or eTA-only entry to ~170 destinations including the US (under the Visa Waiver Program since October 2023, with ESTA), Canada (eTA), the UK, Schengen (with ETIAS from late 2026), Japan, South Korea, and most of Latin America. Several Arab and Muslim-majority states refuse entry to Israeli passport holders or to any passport showing an Israeli stamp — Iran, Iraq, Lebanon, Syria, Yemen, Libya, Algeria, and (in practice if not always policy) Saudi Arabia, Bangladesh, Brunei, Malaysia and Pakistan. Always travel with a clean second passport for onward travel via those regions.`,

  SA: `The Saudi Arabian passport has improved significantly in mobility rankings since 2018, offering visa-free or visa-on-arrival entry to ~85 destinations including the UK (6 months visa-free for short stays since 2022 with electronic permit), Schengen (90/180 — visa required), Japan (visa required), Singapore, and most of the GCC. The US and most of Schengen require embassy visas. Saudi nationals benefit from GCC reciprocity — free residence and work across Kuwait, Bahrain, Qatar, the UAE and Oman — and from the unified GCC tourist visa as it rolls out across 2024–2026. Long-stay routes outside the GCC commonly use UAE Golden Visa equivalents.`,

  QA: `The Qatari passport offers visa-free or visa-on-arrival entry to ~110 destinations including the Schengen Area (90/180, with ETIAS from late 2026), the UK (visa-free since 2022 with electronic permit), Singapore, Japan, South Korea, Malaysia, and most of Latin America. The US requires a B1/B2 visa. Qatari nationals benefit from GCC reciprocity (residence and work rights across Bahrain, Kuwait, Oman, Saudi Arabia, and the UAE) and from the rolling-out unified GCC tourist visa as Tier-1 eligibility is confirmed through 2026. Qatar's modest national population and high consular-service investment make passport renewals fast.`,

  KW: `Kuwait was the first GCC state to win Schengen visa-free entry (2014) and reached the same status with Japan (2026 reciprocal arrangement under negotiation). Kuwaiti nationals enter the UK with an electronic permit (from 2024) and travel to Russia, Türkiye, Malaysia, Singapore and Thailand without a visa. The US remains an embassy-application route. Inside the GCC, Kuwaitis work and reside as nationals across Bahrain, Oman, Qatar, Saudi Arabia and the UAE under longstanding reciprocity, and Kuwait's involvement in the rolling unified GCC tourist visa means inbound travel from Tier-1 nationalities streamlines further across 2026.`,

  BH: `The Bahraini passport offers visa-free or visa-on-arrival entry to ~85 destinations including the Schengen Area (90/180, with ETIAS from late 2026), Singapore, Malaysia, and most of Southeast Asia. The UK requires an electronic permit (introduced 2024) and the US requires a B1/B2 visa. Bahraini nationals benefit from GCC reciprocity (free residence and work across Kuwait, Oman, Qatar, Saudi Arabia, and the UAE) and from the rolling-out unified GCC tourist visa for inbound tourism. Long-stay routes outside the GCC commonly use the UK Skilled Worker and Canada Express Entry.`,

  OM: `The Omani passport provides visa-free or visa-on-arrival entry to ~85 destinations including the Schengen Area (90/180, with ETIAS from late 2026), Singapore, Malaysia, the Maldives, and most of Southeast Asia. The UK requires an electronic permit and the US requires a B1/B2 visa. Omani nationals benefit from GCC reciprocity — free residence and work across Bahrain, Kuwait, Qatar, Saudi Arabia, and the UAE — and from the rolling-out unified GCC tourist visa. Oman's bilateral arrangements within East Africa (Tanzania, Zanzibar historical ties) make regional travel routine.`,

  JO: `The Jordanian passport offers visa-free or visa-on-arrival entry to ~50 destinations, with most major destinations requiring an embassy or e-Visa. Jordanians enter Türkiye, Malaysia, Indonesia (visa-on-arrival), and parts of the Caribbean and South America visa-free. Schengen, the US, the UK, Canada, and Australia all require pre-arrival visas. Jordan has a privileged labour-market arrangement with GCC states (especially Saudi Arabia and the UAE) where Jordanian professionals are heavily represented. The 2022 King Abdullah Initiative for the US provides Jordanian nationals with E-2 treaty-investor visa eligibility — an unusual privilege for the region.`,

  EG: `The Egyptian passport requires visas for most major destinations including the US, the UK, Schengen, Canada, and Australia. Visa-free or visa-on-arrival access is limited but includes parts of Latin America (Bolivia, Ecuador, Peru), several Caribbean states, Türkiye (visa-free since 2017 was suspended in 2023; check current rules), and most of Sub-Saharan Africa under bilateral arrangements. Egyptian nationals are heavily represented in GCC labour markets — Saudi Arabia, Kuwait, the UAE — under sponsored work-permit systems. Long-stay routes into the West commonly use the UK Skilled Worker, Canada Express Entry, and Australia Subclass 482.`,

  MA: `The Moroccan passport requires visas for most Western destinations including the US, the UK, Schengen, Canada, and Australia. Visa-free or visa-on-arrival access is concentrated in Latin America (Argentina, Brazil, Chile, Peru), several Caribbean and Central American states, Türkiye, Malaysia, Indonesia, and most of Sub-Saharan Africa. Morocco maintains strong bilateral ties with France and Spain — Moroccan-French and Moroccan-Spanish dual nationality is common — supporting family-reunification and student routes into both. Long-stay options use the EU Blue Card, France's "Talent Passport", Spain's Highly Qualified Professional visa, and Canada Express Entry.`,

  TN: `The Tunisian passport requires visas for most Western destinations including the US, the UK, Schengen, Canada, and Australia. Visa-free or visa-on-arrival access includes Türkiye, Malaysia, Indonesia, several Latin American states (Bolivia, Ecuador, Peru, Honduras), most of Sub-Saharan Africa, and parts of Eastern Europe (Serbia, Belarus, North Macedonia). Tunisian nationals benefit from the EU-Tunisia Mobility Partnership which supports skilled migration to France, Germany, Italy, and Belgium under preferential visa categories. France remains the dominant migration destination historically, with established diaspora communities supporting family-reunification and education-based pathways into the EU.`,

  KE: `The Kenyan passport provides visa-free or visa-on-arrival entry to most of Africa (under the African Continental Free Trade Area and various bilateral arrangements), the East African Community Tourist Visa zone (Kenya–Rwanda–Uganda single visa), several Caribbean and Pacific states, Türkiye, and parts of Southeast Asia. Schengen, the UK, the US, Canada, and Australia all require embassy visas — though UK refusal rates for Kenyan applicants have declined since 2023. Long-stay routes commonly use the UK Skilled Worker (especially for healthcare professionals), Canada Express Entry, and Australia Subclass 482.`,

  NG: `The Nigerian passport requires visas for most destinations and is among the more difficult passports for short-stay travel. Visa-free or visa-on-arrival access is concentrated in ECOWAS member states (free movement, residence, and establishment within the 15-member bloc) and a small number of Caribbean and Pacific states. UK, US, Schengen and Canadian visa applications carry above-baseline refusal rates (30–50% historically) — strong documentation materially improves outcomes. Long-stay routes into the West use the UK Skilled Worker (Nigerian nationals are among the top issuance cohorts), Canada Express Entry, and Australia Subclass 482.`,

  GH: `The Ghanaian passport provides visa-free movement within ECOWAS (free entry, residence, and establishment across 15 West African states) plus visa-free or visa-on-arrival entry to several Caribbean states, parts of East Africa, and a small Asian list (Malaysia, Indonesia visa-on-arrival). Most major destinations — the US, UK, Schengen, Canada, Australia — require embassy visas. Ghana is a high-volume issuing country for the UK Skilled Worker (healthcare especially), Canada Express Entry, and US Diversity Visa Lottery participation. Bilateral working-holiday or youth-mobility agreements are limited.`,

  GY: `The Guyanese passport grants CARICOM Single Market and Economy rights (free movement, residence, and the right to establish a business across 12 member states) plus visa-free or visa-on-arrival entry to the UK (6 months visa-free), the Schengen Area (90/180, with ETIAS from late 2026), most of Latin America, and parts of Southeast Asia. The US requires a B1/B2 visa. Guyana's significant Indian-descent population maintains close ties with India (overseas-citizen card eligible), supporting bilateral cultural and educational exchange. Long-stay routes commonly use Canada Express Entry and the UK Skilled Worker.`,

  JM: `The Jamaican passport provides CARICOM Single Market and Economy rights (free movement and residence across 12 member states), visa-free entry to the UK (6 months), Hong Kong, Singapore, and most of Latin America, plus visa-on-arrival in several African and Asian states. The US, Schengen, Canada and Australia require embassy visas. Jamaica's deep diaspora ties with the UK, the US, and Canada support extensive family-reunification routes. Commonwealth status grants Jamaicans preferential treatment under the UK's Youth Mobility scheme and several historical reciprocal arrangements.`,

  TT: `The Trinidad and Tobago passport grants CARICOM Single Market and Economy rights, visa-free entry to the UK (6 months), the Schengen Area (90/180, with ETIAS from late 2026), Hong Kong, Singapore, Malaysia, and most of Latin America. The US requires a B1/B2 visa. Trinidad and Tobago's mixed Indian-African heritage supports both Indian Overseas Citizen eligibility and dense ties to the African diaspora. Long-stay routes use Canada Express Entry (the largest Trinidadian migration destination), the UK Skilled Worker, and Commonwealth youth-mobility schemes.`,

  DO: `The Dominican Republic passport offers visa-free or visa-on-arrival entry to ~75 destinations including the Schengen Area (90/180, with ETIAS from late 2026), the UK (6 months visa-free), Hong Kong, Singapore (visa-on-arrival), Türkiye, and most of Latin America. The US, Canada and Australia require embassy visas. CAFTA-DR (the Central American Free Trade Agreement) supports business travel preferences with the US. Dominican nationals are heavily represented in US migration via family-sponsorship, and Spain's bilateral conventions (rooted in the Iberoamerican framework) provide simplified naturalisation after two years of legal residence.`,

  CR: `The Costa Rican passport provides visa-free or eTA-only entry to ~150 destinations including the Schengen Area (90/180, with ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA), Hong Kong, Singapore, Japan, South Korea (K-ETA), and most of Latin America. The US requires a B1/B2 visa. Costa Rica's neutrality, lack of a standing army, and stable institutions support strong consular service abroad. CAFTA-DR provides business travel preferences with the US. Spain's Iberoamerican naturalisation framework grants Costa Ricans simplified Spanish citizenship after two years of legal residence.`,

  PA: `The Panamanian passport offers visa-free or eTA-only entry to ~140 destinations including the Schengen Area (90/180, with ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA), Hong Kong, Singapore, Japan, South Korea (K-ETA), and most of Latin America. The US requires a B1/B2 visa. Panama's status as a financial hub means many ordinary passports also hold a second nationality. Spain's Iberoamerican naturalisation framework grants Panamanians simplified Spanish citizenship after two years of legal residence. Bilateral arrangements with Colombia, Costa Rica and Ecuador support border-region commerce.`,

  GT: `The Guatemalan passport offers visa-free or eTA-only entry to ~130 destinations including the Schengen Area (90/180, with ETIAS from late 2026), the UK (6 months visa-free), Hong Kong, Singapore (visa-on-arrival), Japan, South Korea (K-ETA), and most of Latin America under the CA-4 Border Control Agreement (Guatemala–El Salvador–Honduras–Nicaragua free movement of citizens). The US, Canada, and Australia require embassy visas. CAFTA-DR provides business-travel preferences with the US. Spain's Iberoamerican naturalisation framework grants Guatemalans simplified Spanish citizenship after two years of legal residence — a major route into the EU for Guatemalan professionals.`,

  CO: `The Colombian passport grants visa-free or eTA-only entry to ~135 destinations including the Schengen Area (90/180, with ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA, granted in 2022), Hong Kong, Singapore, Japan, South Korea (K-ETA), and most of Latin America. The US requires a B1/B2 visa. Mercosur association membership and the Pacific Alliance support residency rights across Argentina, Brazil, Chile, Mexico, Peru and Uruguay. Spain's bilateral arrangements (and Iberoamerican naturalisation) grant Colombians simplified Spanish citizenship after two years of residence — a major migration route.`,

  PE: `Peru's passport has improved sharply since Schengen visa exemption arrived in 2016 — 135+ destinations now open without prior authorisation, including the UK, Israel, Türkiye, the Russian Federation, and most of Asia from Japan to Malaysia. The US and Canada remain embassy-application destinations. The Andean Community (Peru, Bolivia, Colombia, Ecuador) creates free movement and labour rights across the Andean north of the continent, distinct from Mercosur. Peru's growing Japanese-Peruvian community supports the Nikkei Visa route into Japan — a heritage-based long-stay channel unique to citizens of partial Japanese descent.`,

  CL: `The Chilean passport ranks among the strongest in the Americas, with visa-free or eTA-only entry to ~175 destinations including the US (ESTA, granted in 2014 — the only South American Visa Waiver Program member), Canada (eTA), the Schengen Area (90/180, with ETIAS from late 2026), the UK (6 months visa-free), Australia (eVisitor), Hong Kong, Singapore, Japan, and South Korea (K-ETA). Working-holiday agreements include Australia, New Zealand, Canada, Germany, France, Japan, and South Korea. Pacific Alliance and Mercosur association memberships add Latin American residency rights, and Spain's Iberoamerican naturalisation simplifies Spanish citizenship.`,

  AR: `The Argentine passport provides visa-free or eTA-only entry to ~170 destinations including the Schengen Area (90/180, with ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA, granted in 2022), Hong Kong, Singapore, Japan, South Korea (K-ETA), Australia (eVisitor), and most of Latin America. The US requires a B1/B2 visa (Argentina was in the Visa Waiver Program until 2002). Working-holiday agreements include Australia, New Zealand, Canada, Germany, France, Japan, and South Korea. Mercosur full-member status grants residency rights across Brazil, Paraguay, Uruguay, and associated states.`,

  UY: `Uruguay holds the second-strongest South American passport behind Chile — its tiny size (3.4M people) belies the breadth: 155+ destinations open without prior visa, including Schengen, the UK, Israel, Hong Kong, Singapore, Russia, and an eVisitor route into Australia. Only the US, Canada and a small list of African/Asian destinations require embassy applications. Uruguay's three Mercosur founding partners (Argentina, Brazil, Paraguay) grant near-automatic residency, and Montevideo issues residency to qualifying foreign nationals quickly — an unusual hub for South American expat-citizenship pipelines. Spain's Iberoamerican framework cuts naturalisation to two years.`,

  VE: `The Venezuelan passport requires visas for most major destinations including the US, Canada, and most of Schengen since 2024 (when Spain, Italy and the Netherlands tightened rules in response to migration pressures). Visa-free or visa-on-arrival access remains in most of Latin America under Mercosur association, the Andean Community, and bilateral arrangements; Türkiye, Iran, Russia, and Serbia also remain open. Passport issuing and renewal are severely constrained — many Venezuelans abroad cannot renew. Spain, Argentina, Mexico, Chile, Uruguay, Peru and Colombia operate streamlined regularization programmes for Venezuelan migrants.`,

  PK: `The Pakistani passport sits among the most travel-restricted globally. Visa-free or visa-on-arrival access is limited to a handful of destinations — primarily the Maldives, several Caribbean states, parts of East Africa, and Cape Verde. Most major destinations including the US, the UK, Schengen, Canada, and Australia require embassy visas. Pakistani applicants face above-baseline refusal rates for short-stay visas (30–60% historically). Long-stay routes are dominated by the UK Skilled Worker (especially healthcare), Canada Express Entry, Australia Subclass 482, and the US H-1B — Pakistani nationals are heavily represented in all four programmes.`,

  BD: `The Bangladeshi passport offers visa-free or visa-on-arrival entry to ~40 destinations, primarily in Sub-Saharan Africa, the Caribbean, several Pacific island states, and parts of South and Southeast Asia. Most major destinations — the US, UK, Schengen, Canada, Australia — require embassy visas, with B1/B2 interview waits at the Dhaka US embassy historically running 6–12 months. Bangladeshi nationals are heavily represented in UK Skilled Worker, Canada Express Entry, Australia Subclass 482, US H-1B, and Gulf labour markets (Saudi Arabia, the UAE, Kuwait, Qatar). UK Bangladeshi-heritage family-reunification routes remain among the largest UK immigration categories.`,

  LK: `The Sri Lankan passport offers visa-free or visa-on-arrival entry to ~40 destinations primarily in Sub-Saharan Africa, the Caribbean, several Pacific states, and parts of Southeast Asia. Most major destinations require embassy or e-Visa applications. Bilateral working-holiday agreements with Australia, New Zealand, and Japan are limited. Long-stay routes commonly use the UK Skilled Worker (healthcare and tech), Canada Express Entry, Australia Subclass 482, and the US H-1B. The Sri Lankan diaspora — particularly large in Canada, the UK, and Australia — supports extensive family-reunification migration.`,

  TH: `The Thai passport offers visa-free or visa-on-arrival entry to ~85 destinations including ASEAN free movement (30–90 day stays in Malaysia, Singapore, Indonesia, the Philippines, Vietnam, Laos, Cambodia, Myanmar, Brunei), Hong Kong, Macau, Japan (15 days visa-free), South Korea (K-ETA), Türkiye, Iran, and most of South America. The US, UK, Schengen, Canada, and Australia all require embassy visas. China granted Thai citizens 30-day visa-free entry in 2024 under a reciprocal arrangement. Long-stay options to the West are typically employer-sponsored, especially UK Skilled Worker (hospitality, healthcare), Canada Express Entry, and the US E-2 treaty-investor visa.`,

  MY: `The Malaysian passport ranks among the strongest in Southeast Asia, with visa-free or eTA-only access to ~180 destinations including the US (ESTA — Malaysia is in the Visa Waiver Program), the UK (ETA from 2025), Schengen (90/180, with ETIAS from late 2026), Canada (eTA), Japan, South Korea (K-ETA), and most of Southeast Asia under ASEAN. Working-holiday agreements with Australia and New Zealand are available. Long-stay routes include the UK Skilled Worker, Canada Express Entry, the US H-1B, Australia Subclass 482, and Singapore's Employment Pass. Malaysia's My Second Home (MM2H) programme attracts foreign retirees but is for inbound migration, not outbound.`,

  ID: `The Indonesian passport requires advance visas for most major Western destinations including the US, UK, Schengen, Canada, and Australia. Visa-free or visa-on-arrival access covers ~70 destinations, primarily ASEAN free-movement partners (30 days in Malaysia, Singapore, Thailand, etc.), the Maldives, Hong Kong, Macau, Türkiye, and several African and South American states. Japan grants 15-day visa-free entry to Indonesian e-passport holders who pre-register with the Japanese embassy. Long-stay routes commonly use the UK Skilled Worker (hospitality, healthcare), Australia Subclass 482, US H-1B, Canada Express Entry, and Gulf labour markets (UAE, Saudi Arabia, Qatar) for domestic and skilled work.`,

  PH: `The Philippine passport offers visa-free or visa-on-arrival entry to ~70 destinations including ASEAN free movement (30 days in Singapore, Thailand, Malaysia, Indonesia, Vietnam, Laos, Cambodia, Myanmar, Brunei), Hong Kong, Macau, Brazil, and several Caribbean states. The US, UK, Schengen, Canada, Australia, and Japan all require embassy visas. South Korea is on the K-ETA scheme. Filipino nationals are among the most heavily migrant workforce globally — the OFW (Overseas Filipino Worker) framework supports placement in the Gulf states, Hong Kong, Singapore, Canada, and the US. UK Skilled Worker (healthcare and care work) and Canada Caregiver Pathways are common long-stay routes.`,

  VN: `The Vietnamese passport offers visa-free or visa-on-arrival entry to ~55 destinations, mostly ASEAN free-movement partners (Thailand, Singapore, Malaysia, Indonesia, the Philippines, Laos, Cambodia, Myanmar, Brunei — 14 to 30 days), plus several African and Caribbean states. Most major destinations including the US, UK, Schengen, Canada, Australia, Japan, and South Korea require embassy visas. China was granted reciprocal visa-free access in 2025. Long-stay routes use the UK Skilled Worker (technology and healthcare), Canada Express Entry, Australia Subclass 482, the US H-1B, and South Korean E-7 (foreign professional) and E-9 (employment of non-professionals — EPS) categories.`,

  UA: `The Ukrainian passport, since the 2017 EU visa liberalisation, grants visa-free Schengen entry for 90 days in 180 (ETIAS from late 2026), plus UK (6-month visa-free), Israel, Türkiye, the Western Balkans, and most of Latin America. The US, Canada, Australia and Japan still require visas. Since 2022, Ukrainian citizens have benefited from extraordinary temporary-protection schemes: the EU's Temporary Protection Directive (3-year renewable residence + work right across all member states), the UK's Homes for Ukraine and Ukraine Family Schemes, the US's Uniting for Ukraine humanitarian parole, and Canada's CUAET emergency travel authorisation. Long-stay migration outside these schemes uses Skilled Worker and Express Entry channels.`,

  NP: `The Nepali passport offers visa-free or visa-on-arrival entry to ~40 destinations, primarily in South Asia (India under the 1950 Indo-Nepal Treaty grants near-unlimited right of work and residence), the Maldives, Sri Lanka (visa-on-arrival), and several African states. The US, UK, Schengen, Canada, Australia, and Japan all require embassy visas, with relatively high refusal rates for B1/B2 and Schengen short-stay. Long-stay routes are dominated by Gulf labour migration (especially Saudi Arabia, the UAE, Qatar, Malaysia under labour-export agreements), UK Skilled Worker (hospitality, healthcare), and student visas to Australia, the US, and the UK.`,

  KZ: `The Kazakh passport offers visa-free or visa-on-arrival entry to ~80 destinations, including most of Central Asia under the CIS framework, Türkiye (90 days), Belarus, Russia, Armenia, Kyrgyzstan, Georgia, Israel, the UAE (30 days, expanded 2024), and most of Latin America. The US, UK, Schengen, Canada, Japan and Australia require embassy visas. The Eurasian Economic Union (EAEU) grants Kazakh citizens labour-market access in Russia, Belarus, Armenia, and Kyrgyzstan. Long-stay routes to the West commonly use the UK Skilled Worker, Canada Express Entry, the US H-1B, and Australian Subclass 482, with technical and energy-sector expertise well-represented.`,

  GE: `The Georgian passport — since the 2017 EU visa liberalisation — grants Schengen 90/180 visa-free entry (ETIAS from late 2026), plus the UK (6-month visa-free), Türkiye (90 days), Iran, Israel, and most of South America. The US and Canada require visas. Georgia's "open visa" policy reciprocates extraordinarily generously inbound (over 90 nationalities enter Georgia visa-free for up to 365 days). Outbound long-stay routes use the UK Skilled Worker, Canada Express Entry, the US H-1B, and Germany's Blue Card. Georgia's CETA/EU Association Agreement deepens commercial mobility with the EU.`,

  ET: `The Ethiopian passport offers visa-free or visa-on-arrival entry to ~40 destinations, primarily in Sub-Saharan Africa (East African Community partners — Kenya, Tanzania, Uganda, Rwanda — under the EAC tourist visa framework), the Caribbean (Dominica, Haiti), and a small number of Pacific island states. Most major destinations including the US, UK, Schengen, Canada, Australia, China, and Japan require embassy visas. The substantial Ethiopian diaspora in the US (Washington DC, Minneapolis), the UK, Canada and the Gulf supports family-reunification migration. UK Skilled Worker (healthcare in particular) and Gulf labour markets are dominant employment-based pathways.`,

  UG: `The Ugandan passport offers visa-free or visa-on-arrival entry to ~55 destinations, primarily in East Africa (EAC free movement to Kenya, Tanzania, Rwanda, Burundi, South Sudan) and parts of the Sahel + Indian Ocean. The US, UK, Schengen, Canada, Australia, and most of Asia require embassy visas. UK Health and Care Worker visa is a major route for Ugandan nurses + care workers (NHS / private-care recruitment). Canada Express Entry and Australia Subclass 482 represent additional skilled-migration channels. EAC Single Tourist Visa simplifies tourism within Kenya / Rwanda / Uganda for both inbound and Ugandan-outbound regional travel.`,

  TZ: `The Tanzanian passport offers visa-free or visa-on-arrival entry to ~50 destinations including EAC free movement (Kenya, Uganda, Rwanda, Burundi, South Sudan), SADC tourism arrangements with Southern African states, and several Indian Ocean / Caribbean states. The US, UK, Schengen, Canada, Australia, China require embassy visas. Long-stay routes are dominated by UK Skilled Worker (healthcare especially), Gulf labour markets (Saudi Arabia, UAE, Qatar), Canada Express Entry, and US H-1B / EB-3 channels. Tanzanian-British community ~30,000 — a long-standing diaspora supports family-reunification pipelines.`,

  AO: `The Angolan passport offers visa-free or visa-on-arrival entry to ~50 destinations including SADC partner states, the CPLP Mobility Framework (2021) bilateral arrangements with Portugal, Brazil, Cabo Verde, Mozambique, and Sao Tome, and several Caribbean states. Most major destinations including the US, UK, Schengen, Canada, Australia, and most of Asia require embassy visas. Portugal remains the dominant long-stay destination for Angolans — D7 (passive income), D2 (entrepreneur), and CPLP-streamlined residence permits. Brazil similarly accessible under MERCOSUR-association + CPLP frameworks. UK Skilled Worker (oil + gas, healthcare) is an active employment route.`,

  ZW: `The Zimbabwean passport offers visa-free or visa-on-arrival entry to ~50 destinations primarily in Southern Africa under SADC tourism arrangements (Mozambique, Namibia, Zambia, Malawi, etc.), and several Indian Ocean / Caribbean states. The US, UK, Schengen, Canada, Australia, and Japan require embassy visas. UK Ancestry visa is a major route for Zimbabweans of British-born grandparent descent (Commonwealth route — 5-year work-permitting visa leading to ILR). The substantial Zimbabwean diaspora in the UK (~250k+) supports family-reunification pipelines. South Africa is the dominant labour-market destination for outbound Zimbabwean migration; UK and Australia secondary.`,

  MM: `The Myanmar (Burmese) passport sits among the more travel-restricted documents globally, with visa-free or visa-on-arrival entry to ~40 destinations — primarily ASEAN partner states (Cambodia, Laos, Vietnam, Indonesia, Brunei) and select Indian Ocean states. Most major destinations require embassy visas. Refusal rates for US B-1/B-2 and Schengen short-stay are elevated for Burmese applicants. Long-stay migration via UK Skilled Worker (healthcare), Australia Subclass 482, US H-1B / family-reunification, and Thailand Non-Imm B (substantial Burmese workforce in Thai construction + factories). Myanmar's political situation since 2021 has constrained both inbound and outbound mobility through embassy closures.`,

  KH: `The Cambodian passport offers visa-free or visa-on-arrival entry to ~55 destinations, primarily ASEAN free-movement partners (Thailand, Vietnam, Laos, Myanmar, Indonesia, Brunei, Singapore, Malaysia, Philippines — 14 to 30 days), Hong Kong, Macau, and several African / Caribbean states. The US, UK, Schengen, Canada, Australia, Japan, and South Korea require embassy visas. Long-stay routes use UK Skilled Worker (hospitality, healthcare), Australia Subclass 482, US H-1B, and Korean E-7/E-9 (Employment Permit System for blue-collar workers). The Cambodian-American community ~330k supports family-reunification migration.`,

  LA: `The Lao passport offers visa-free or visa-on-arrival entry to ~50 destinations, primarily ASEAN free-movement partners (Thailand, Vietnam, Cambodia, Myanmar — 14 to 30 days), Hong Kong (90 days visa-free), and several Indian Ocean states. The US, UK, Schengen, Canada, Australia, Japan, and South Korea require embassy visas. Long-stay routes primarily use Thai work permits (substantial Lao workforce in Thai agriculture + construction) and the Korean E-9 EPS. Lao-American community ~262k (descendants of Vietnam War refugees) supports family-reunification migration via I-130 petitions.`,

  AF: `The Afghan passport ranks at or near the bottom of global passport mobility indexes. Visa-free or visa-on-arrival entry covers fewer than 30 destinations, primarily in the post-Soviet space and a small number of Africa and Indian Ocean states. All major Western destinations require embassy visas with very high refusal rates. The 2021 humanitarian crisis triggered extraordinary protection schemes in the US (Operation Allies Welcome / SIV), UK (ARAP / ACRS), Canada (special-measures), Germany (Federal Admission Programme), and Australia (Afghan Locally-Engaged Employees programme). Outside these schemes, long-stay migration is constrained — most Afghans approach via asylum routes.`,

  IR: `The Iranian passport sits among the more travel-restricted documents globally, with visa-free or visa-on-arrival entry to ~40 destinations primarily in Latin America (Venezuela, Bolivia, Ecuador), the Caucasus (Armenia, Georgia until 2024 tightening), and parts of Africa. Most major Western destinations require embassy visas; sanctions-related complications affect Iranian applications for the US (since 2017 travel ban revisions), UK, EU, Canada, Australia, Japan. Long-stay migration via embassy visas faces enhanced scrutiny + extended administrative processing. Substantial Iranian diaspora in the US (Los Angeles especially), Canada (Toronto + Vancouver), Germany, UK, and Australia supports family-reunification routes.`,

  IQ: `The Iraqi passport offers visa-free or visa-on-arrival entry to ~30 destinations, primarily in select Middle Eastern + Latin American states. Most major destinations including the US, UK, Schengen, Canada, Australia, China, and Japan require embassy visas. UK Skilled Worker, Canada Express Entry, US Special Immigrant Visa (SIV — for Iraqi-allied wartime employees), Germany Federal Admission Programme, and Australia humanitarian visas have all been used substantially since 2014. The Iraqi diaspora in the US (Detroit, San Diego), UK, Sweden, Germany, and Jordan supports both family-reunification and humanitarian-resettlement pipelines.`,

  LB: `The Lebanese passport offers visa-free or visa-on-arrival entry to ~40 destinations, primarily Latin America (Venezuela, Brazil, Ecuador), select African states, and a small number of Caribbean and Pacific islands. Most major destinations including the US, UK, Schengen, Canada, Australia, and Japan require embassy visas. The substantial Lebanese diaspora in Brazil (~7M people of Lebanese descent), Argentina, France, the US, Canada, and Australia supports both family-reunification and heritage-citizenship routes. France's Lebanese-French historical ties simplify some long-stay arrangements via Talent Passport + Visiteur visas. UK Skilled Worker (healthcare especially) is an active employment route.`,

  BY: `The Belarusian passport offers visa-free or visa-on-arrival entry to ~70 destinations including the post-Soviet space (Russia, Armenia, Kazakhstan, Kyrgyzstan — labour-market access under EAEU), Türkiye (90 days), Israel, the UAE, and most of South America. The EU suspended visa-free arrangements for Belarus in 2022; Schengen short-stay now requires an embassy visa with extended administrative processing. UK, US, Canada, Australia, and Japan all require embassy visas. Long-stay migration to EU member states (especially Poland and Lithuania, which run extraordinary humanitarian schemes for Belarusian opposition figures), the US, and Canada has accelerated since 2020.`,

  MD: `The Moldovan passport — since the 2014 EU visa liberalisation — grants Schengen 90/180 visa-free entry (ETIAS from late 2026), plus UK (6-month visa-free), Israel, Türkiye, Western Balkans, and most of Latin America. The US, Canada, Australia, and Japan still require embassy visas. Moldova's EU candidacy (granted 2022) has deepened mobility for educational and skilled-worker pipelines into Romania, Poland, Germany, Italy. Romanian citizenship is available to Moldovans on demonstration of Romanian-language proficiency + Romanian-ancestry connection — historically a major route into the EU for ethnic-Romanian Moldovans.`,

  AL: `The Albanian passport — since the 2010 Schengen visa liberalisation — grants 90/180 visa-free entry to the Schengen Area (ETIAS from late 2026), plus the UK (6-month visa-free since 2024 ETA rollout exemption review), Türkiye (90 days), most of the Western Balkans + Latin America. The US, Canada, Australia, and Japan still require embassy visas. Italy in particular has historically been the dominant long-stay destination for Albanians (substantial Italian-Albanian community); Greece + Germany follow. EU candidacy and the Western Balkans 2024 Growth Plan support deepened economic integration. UK Skilled Worker (healthcare, construction) and Canada Express Entry are growing routes.`,

  BA: `The Bosnia and Herzegovina passport — since the 2010 Schengen visa liberalisation — grants 90/180 visa-free entry to the Schengen Area (ETIAS from late 2026), plus the UK (6-month visa-free), Türkiye (90 days), most of the Western Balkans, and most of Latin America. The US, Canada, Australia, and Japan require embassy visas. Germany hosts the largest Bosnian diaspora outside Bosnia (~370k), with Austrian and Slovenian communities also substantial. UK Skilled Worker (healthcare, construction, hospitality) is an active employment route. EU candidacy (granted 2022) is in early stages; mobility deepening expected through accession.`,

  RS: `The Serbian passport — since the 2010 Schengen visa liberalisation — grants 90/180 visa-free entry to Schengen Area (ETIAS from late 2026), plus the UK (6-month visa-free), Türkiye (90 days), Russia (30 days, longstanding bilateral), China (30 days mutual visa-free since 2017 — the only European country with this arrangement), and most of Latin America. The US, Canada, Australia, and Japan require embassy visas. EU candidacy ongoing. Substantial Serbian diaspora in Germany, Austria, Switzerland, Australia, US, and Canada supports family-reunification migration. The unique Russia + China mutual visa-free arrangements make Belgrade a hub for travellers seeking those routes.`,

  MK: `The North Macedonian passport — since the 2010 Schengen visa liberalisation — grants 90/180 visa-free entry to Schengen Area (ETIAS from late 2026), plus the UK (6-month visa-free), Türkiye (90 days), most of the Western Balkans, and most of Latin America. The US, Canada, Australia, and Japan require embassy visas. EU candidacy (since 2005) continues; full accession blocked historically by Greek + Bulgarian disputes (Greek dispute resolved 2019; Bulgarian dispute over historical/linguistic claims pending). The North Macedonian community in Germany, Switzerland, Italy, US, and Australia supports family-reunification migration. UK Skilled Worker (healthcare, construction) is an active route.`,

  AZ: `The Azerbaijani passport offers visa-free or visa-on-arrival entry to ~75 destinations including most of the post-Soviet space (Russia, Belarus, Armenia, Kazakhstan, Kyrgyzstan, Türkiye, Iran, Israel), the GCC states (UAE 30 days), and most of Latin America. The US, UK, Schengen, Canada, Australia, and Japan require embassy visas. CIS labour-market access supports substantial Azerbaijani-Russian working relationships. Long-stay migration to the West uses UK Skilled Worker, Canada Express Entry, the US H-1B, and Germany Blue Card. Azerbaijan's strategic relationships with Türkiye + Israel + UAE support frequent business travel.`,

  BS: `The Bahamian passport offers visa-free or visa-on-arrival entry to ~155 destinations including the Schengen Area (90/180, with ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA), Hong Kong, Singapore, Japan, and most of CARICOM under the Single Market and Economy framework. The US requires a B1/B2 visa despite the geographic proximity. CARICOM Skilled National scheme supports residence + work rights across 12 Caribbean member states. CBI / golden-residence programmes — Bahamas is not a CBI seller but a beneficiary nation for ultra-high-net-worth global mobility. Cayman + Bermuda + BVI labour markets accessible via OCT (Overseas Country and Territory) arrangements.`,

  // ─── CRITICAL TOP-20 GAPS ───
  FR: `The French passport ranks among the most travel-friendly globally, granting visa-free or eTA-only access to ~190 destinations. As an EU member, France offers freedom of movement throughout the European Union and EEA, plus Schengen short-stay access. French citizens travel visa-free to the United States (ESTA), Canada (eTA), Australia (eVisitor), the UK (ETA from 2025), Japan, South Korea, the UAE, and most of Latin America + Southeast Asia. France's overseas departments (Martinique, Guadeloupe, French Guiana, Réunion, Mayotte) give French citizens unique footholds across three continents. Working-holiday agreements with Australia, NZ, Canada, Japan, Korea, Argentina, Chile, Colombia, Mexico, Taiwan, Hong Kong. France-Quebec mobility accords + the OIF (Francophonie) supports continued mobility across French-speaking Africa + the Caribbean.`,
  PT: `The Portuguese passport offers EU/EEA free movement, Schengen Area access, and visa-free or eTA-only entry to ~190 destinations including the United States (ESTA), Canada (eTA), the UK (ETA from 2025), Japan, South Korea, Australia (eVisitor), and most of Latin America + Southeast Asia. Portuguese citizens have unique CPLP (Community of Portuguese Language Countries) reciprocity — Brazil, Angola, Mozambique, Cape Verde, Guinea-Bissau, São Tomé and Príncipe, East Timor, Equatorial Guinea — facilitating simplified residence + work + business arrangements. Working-holiday agreements with Australia, NZ, Canada, Japan, Korea. The Portuguese diaspora in France ~1.7M, Brazil ~5M descent, the US ~1.5M, Venezuela, Switzerland makes family-reunification routes uniquely accessible.`,

  // ─── EUROPE — micro-states + gaps ───
  ME: `The Montenegrin passport — since the 2009 Schengen visa liberalisation — grants 90/180 visa-free entry to the Schengen Area (ETIAS from late 2026), plus the UK (6-month visa-free), Türkiye (90 days), Russia (30 days), and most of Latin America + Western Balkans. The US, Canada, Australia, and Japan require embassy visas. EU accession negotiations ongoing (Montenegro is the most advanced Western Balkans candidate). Montenegrin Investor Citizenship Program (CIP) — closed to new applicants as of December 2022 — historically attracted Russian / Chinese / Turkish HNW applicants. Substantial Montenegrin diaspora in Serbia, Turkey, US, Germany, Australia.`,
  XK: `The Kosovo passport offers visa-free entry to a limited number of destinations. Schengen visa liberalisation came into effect January 2024 — Kosovars now travel visa-free to the Schengen Area for 90/180 days (ETIAS from late 2026). Plus Türkiye (90 days), Albania, North Macedonia, Montenegro, most of the Western Balkans + several Latin American + Caribbean states. The UK, US, Canada, Australia, and Japan still require embassy visas. Kosovo's complex international status (~100 UN states recognise it; non-recognition by Russia / China / Serbia / Spain limits some bilateral arrangements). Substantial Kosovo Albanian diaspora in Germany, Switzerland, Austria, Sweden supports family-reunification migration.`,
  AD: `The Andorran passport offers visa-free or eTA-only entry to ~170 destinations including the Schengen Area (Andorra is not a Schengen member, but its citizens have unique de-facto Schengen access via France + Spain — Andorra is landlocked between them), the UK (6-month visa-free), the US (ESTA), Canada (eTA), Japan, South Korea, and most of Latin America. Andorra is in the EU customs union for industrial goods but not the EU. Citizenship is highly restrictive — naturalisation requires 20 years of residence (10 for those who studied in Andorra) + Catalan language fluency + renunciation of foreign citizenship.`,
  MC: `The Monégasque passport offers visa-free or eTA-only entry to ~175 destinations including the Schengen Area (Monaco is not a Schengen member but has open borders with France via the Franco-Monégasque customs union), the UK (6-month visa-free), the US (ESTA), Canada (eTA), Japan, South Korea, Australia (eVisitor), the UAE, and most of Latin America. Monégasque citizenship is exceptionally restrictive (~10 naturalisations per year on average). Monaco is not in the EU but its citizens enjoy bilateral arrangements with France for residence + work. The Monégasque diaspora is small but globally affluent.`,
  SM: `The Sammarinese passport offers visa-free or eTA-only entry to ~175 destinations including the Schengen Area (San Marino is not a Schengen member but is an Italian enclave with open borders), the UK (6-month visa-free), the US (ESTA), Canada (eTA), Japan, South Korea, Australia (eVisitor), and most of Latin America. San Marino is in the EU customs union but not the EU itself. Sammarinese citizens have privileged Italian residence + work arrangements under bilateral conventions dating to the 19th century. Naturalisation requires 25 years of continuous residence.`,
  LI: `The Liechtenstein passport offers EFTA free movement, Schengen Area access, and visa-free or eTA-only entry to ~180 destinations including the United States (ESTA), Canada (eTA), the UK (ETA from 2025), Japan, South Korea, Australia (eVisitor), the UAE, and most of Latin America. Liechtenstein is in EFTA + Schengen but NOT the EU — citizens enjoy EFTA labour-market access via the EEA Agreement. Naturalisation requires 30 years of continuous residence (years before age 20 count double, so 10 years from age 10 would count as 20). Liechtenstein has the strictest naturalisation rules in Europe.`,
  VA: `The Vatican passport is issued only to citizens of Vatican City — primarily the Pope, Cardinals resident in Rome, Apostolic Nuncios, and members of the Swiss Guard. Vatican citizenship is functional (issued for the duration of an office or appointment) rather than birthright. Holders enjoy visa-free or eTA-only entry to ~145 destinations including the Schengen Area (Vatican has open borders with Italy), the UK, US, Canada, most of Latin America. Diplomatic Vatican passports give Holy See diplomats Vienna-Convention immunity at posts globally. Vatican-issued passports are among the rarest globally (~600 active holders).`,

  // ─── LATIN AMERICA & CARIBBEAN — major gaps ───
  EC: `The Ecuadorian passport offers visa-free or visa-on-arrival entry to ~95 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), most of Latin America under Mercosur-associated + UNASUR + CAN frameworks, Russia (90 days), Türkiye (90 days), and most of CARICOM. The US, Canada, Australia, Japan require embassy visas. Ecuadorian diaspora in the US (New York City, Queens especially), Spain (Madrid, Barcelona — heavy 2000s economic migration), Italy supports family-reunification migration. Ecuador uses the US dollar as legal tender — affects cross-border financial flows for migrant remittances.`,
  BO: `The Bolivian passport offers visa-free or visa-on-arrival entry to ~80 destinations including the Schengen Area (90/180, ETIAS from late 2026 — Bolivia joined Schengen visa-free in 2024), most of Latin America under CAN + Mercosur frameworks, Russia (90 days), and most of CARICOM. The US, Canada, Australia, Japan, UK require embassy visas. Bolivian diaspora in Argentina (~1M+, the largest), Spain (heavy 2000s economic migration), Brazil, the US supports family-reunification migration. The Mercosur Residency Agreement supports streamlined Argentine residence + work for Bolivians.`,
  PY: `The Paraguayan passport offers visa-free or visa-on-arrival entry to ~145 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), most of Latin America under Mercosur (full member — free movement within member states), Russia (90 days), Türkiye (90 days), and most of Asia. The US, Canada, Australia, Japan require embassy visas. Paraguayan diaspora in Argentina (~550k, the largest), Spain, Brazil. Mercosur Residency Agreement provides streamlined Argentine + Uruguayan + Brazilian residence.`,
  HN: `The Honduran passport offers visa-free or visa-on-arrival entry to ~135 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), most of Latin America under CAFTA-DR + SICA frameworks. The US, Canada, Australia, Japan require embassy visas. CA-4 (Central America-4) free movement with Guatemala, El Salvador, Nicaragua. Substantial Honduran diaspora in the US ~1M+ (especially Texas, Florida, New York) supports TPS (Temporary Protected Status) + family-reunification migration. Heavy economic migration corridor to the US drives major asylum + irregular migration flows.`,
  NI: `The Nicaraguan passport offers visa-free or visa-on-arrival entry to ~115 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), most of Latin America under SICA + CA-4 frameworks, Russia (visa-free since 2009 — particularly close bilateral), and most of CARICOM. The US, Canada, Australia, Japan require embassy visas. CA-4 free movement with Guatemala, El Salvador, Honduras. Substantial Nicaraguan diaspora in Costa Rica (~500k, the largest outside Nicaragua), the US (Florida especially), Spain supports family-reunification migration.`,
  SV: `The Salvadoran passport offers visa-free or visa-on-arrival entry to ~135 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), most of Latin America under SICA + CA-4 frameworks, Russia (90 days), and most of CARICOM. The US, Canada, Australia, Japan require embassy visas. CA-4 free movement with Guatemala, Honduras, Nicaragua. Massive Salvadoran diaspora in the US ~2.4M (the largest Central American community there, particularly Los Angeles + Washington DC + Houston) supports TPS + family-reunification migration. El Salvador uses the US dollar — close financial integration drives remittance flows.`,
  CU: `The Cuban passport offers visa-free or visa-on-arrival entry to ~60 destinations primarily in Latin America (under bilateral arrangements with Venezuela, Bolivia, Nicaragua), Russia (90 days, longstanding bilateral), the Caucasus + parts of Africa + Asia. The US, UK, Schengen, Canada, Australia, and Japan require embassy visas. US-Cuban relations remain restricted under the embargo — Cuban-Americans rely on family-reunification visas (CFRP) + the Cuban Adjustment Act 1966 (provides a path to US permanent residence after 1 year + 1 day). Substantial Cuban diaspora in the US ~2.3M (Miami especially), Spain ~150k+, Mexico, Venezuela.`,
  HT: `The Haitian passport offers visa-free or visa-on-arrival entry to ~50 destinations primarily in CARICOM (Haiti is a member), select Latin American (Ecuador, Dominica), African, and Pacific island states. The US, UK, Schengen, Canada, Australia, and Japan require embassy visas. The US TPS (Temporary Protected Status) designation for Haitian nationals (continuously extended since the 2010 earthquake) protects ~150k+ Haitians from removal. Substantial Haitian diaspora in the US (Miami, NYC, Boston), Canada (Montreal especially — French-speaking), the Dominican Republic, France, French Guiana supports family-reunification migration.`,
  AG: `The Antigua and Barbuda passport offers visa-free or eTA-only entry to ~150 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA), Hong Kong, Singapore, Russia (90 days), and most of CARICOM under Single Market and Economy. The US requires a B1/B2 visa. Antigua + Barbuda runs an active Citizenship by Investment Program — USD 230k+ for individual, USD 245k+ for family of 4, plus due-diligence fees. CARICOM Skilled National scheme supports residence + work rights across 12 Caribbean member states.`,
  BB: `The Barbadian passport offers visa-free or eTA-only entry to ~165 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA), Hong Kong, Singapore, Japan, and most of CARICOM under Single Market and Economy. The US requires a B1/B2 visa. Barbados has one of the strongest passports in the Caribbean. CARICOM Skilled National scheme supports residence + work rights across 12 Caribbean member states. Barbados Welcome Stamp (remote-worker visa, USD 2,000 fee, 12 months) was Caribbean's pioneer remote-work programme launched 2020.`,
  KN: `The St. Kitts and Nevis passport offers visa-free or eTA-only entry to ~155 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA — under review), Hong Kong, Singapore, Russia (suspension under review), and most of CARICOM under Single Market and Economy. The US requires a B1/B2 visa. St. Kitts + Nevis runs the world's oldest active Citizenship by Investment Program (since 1984) — USD 250k+ donation route or USD 400k+ real-estate route. CBI passports are subject to heightened due-diligence scrutiny in major destination countries.`,
  GD: `The Grenadian passport offers visa-free or eTA-only entry to ~150 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA), China (30 days mutual visa-free — Grenada is one of only four CBI countries with this arrangement), Russia, and most of CARICOM. The US requires a B1/B2 visa. Grenada runs an active Citizenship by Investment Program — USD 235k+ donation route or USD 270k+ real-estate route. Grenada-CBI passports are particularly valued for the unique China visa-free access + the US E-2 treaty-investor visa eligibility (Grenada is an E-2 treaty country).`,
  LC: `The St. Lucia passport offers visa-free or eTA-only entry to ~150 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA), Hong Kong, Singapore, Russia (90 days), and most of CARICOM. The US requires a B1/B2 visa. St. Lucia runs an active Citizenship by Investment Program — USD 240k+ donation route or USD 300k+ real-estate route. CARICOM Skilled National scheme supports residence + work rights across 12 Caribbean member states.`,
  VC: `The St. Vincent and the Grenadines passport offers visa-free or eTA-only entry to ~155 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Canada (eTA), Hong Kong, Singapore, Russia (90 days), and most of CARICOM. The US requires a B1/B2 visa. St. Vincent + the Grenadines does NOT run a Citizenship by Investment Program (one of the few CARICOM states to abstain). CARICOM Skilled National scheme supports residence + work rights across 12 Caribbean member states.`,
  DM: `The Dominican passport (Commonwealth of Dominica, not to be confused with the Dominican Republic) offers visa-free or eTA-only entry to ~145 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Russia (90 days), and most of CARICOM. The US requires a B1/B2 visa. Dominica runs an active Citizenship by Investment Program — USD 200k+ donation route (the lowest entry CBI in the Caribbean) or USD 220k+ real-estate route. CARICOM Skilled National scheme supports residence + work rights.`,
  BZ: `The Belizean passport offers visa-free or eTA-only entry to ~105 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), most of CARICOM (Belize joined CARICOM 1974), Russia (90 days), and most of Latin America. The US, Canada, Australia, Japan require embassy visas. Belize is unique in Central America as a Commonwealth realm member with King Charles III as Head of State — anglophone, English common-law system. CARICOM Skilled National scheme supports residence + work rights across 12 member states.`,

  // ─── AFRICA — major gaps ───
  DZ: `The Algerian passport offers visa-free or visa-on-arrival entry to ~55 destinations primarily across Africa (AU member, ECOWAS observer arrangements), Türkiye (90 days), Russia, Iran, and select Asian + Caribbean states. The Schengen Area, UK, US, Canada, Australia, Japan all require embassy visas. Substantial Algerian diaspora in France ~1.5M (the largest by far, dating to colonial-era + post-1962 independence migration), Belgium, Spain, Canada (Quebec) supports family-reunification migration. France-Algeria mobility is governed by the 1968 bilateral accord (separate from EU general rules). Algeria-Tunisia + Algeria-Morocco land-border restrictions affect regional mobility.`,
  SN: `The Senegalese passport offers visa-free or visa-on-arrival entry to ~65 destinations primarily within ECOWAS (free movement among 15 member states), AU, plus several Latin American + Caribbean states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. ECOWAS Protocol on Free Movement provides streamlined regional integration. Substantial Senegalese diaspora in France ~120k (especially Île-de-France), Italy, Spain, the US supports family-reunification migration. Bilateral France-Senegal mobility arrangements particularly dense via Francophonie + colonial-era ties.`,
  CI: `The Ivorian (Côte d'Ivoire) passport offers visa-free or visa-on-arrival entry to ~65 destinations primarily within ECOWAS (free movement among 15 member states), AU, plus several Latin American + Caribbean + Pacific states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Ivorian diaspora in France ~80k (especially Île-de-France), Burkina Faso (substantial cross-border community), Italy, Belgium supports family-reunification migration. Côte d'Ivoire is Francophone West Africa's largest economy — Abidjan hosts the African Development Bank (AfDB) HQ.`,
  CM: `The Cameroonian passport offers visa-free or visa-on-arrival entry to ~50 destinations primarily within ECCAS (Economic Community of Central African States — limited functional free movement), AU, plus several Caribbean + Asian states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Cameroonian diaspora in France ~90k, the US (especially Maryland, Texas), Germany, Belgium, UK supports family-reunification migration. Cameroon is bilingual (French + English) — unique among AU member states — supporting mobility into both Francophone + Anglophone destinations.`,
  GA: `The Gabonese passport offers visa-free or visa-on-arrival entry to ~55 destinations primarily within ECCAS (limited functional free movement), AU, plus several Caribbean + Pacific states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Gabonese diaspora in France ~30k (especially Île-de-France), Belgium, the US supports family-reunification migration. Gabon hosts substantial expatriate communities from France + China + Lebanon supporting oil + manganese + timber industries — Bongo-family historical ties to France particularly dense.`,
  ML: `The Malian passport offers visa-free or visa-on-arrival entry to ~55 destinations primarily within ECOWAS (suspended after July 2023 coup — pending negotiations), AU, plus several Caribbean + Pacific states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. ECOWAS Protocol on Free Movement traditionally provides streamlined regional integration. Substantial Malian diaspora in France ~120k (especially Île-de-France — heritage from 1960s-70s + ongoing economic migration), Côte d'Ivoire, Senegal supports family-reunification migration. Post-2023 ECOWAS withdrawal affects ECOWAS Travel Certificate arrangements.`,
  BF: `The Burkinabé passport offers visa-free or visa-on-arrival entry to ~55 destinations primarily within ECOWAS (suspended after September 2022 coup — pending negotiations), AU, plus several Caribbean + Pacific states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. ECOWAS Protocol on Free Movement traditionally provides streamlined regional integration. Substantial Burkinabé diaspora in Côte d'Ivoire ~3M+ (the largest Burkinabé community outside Burkina Faso), Ghana, Mali, France supports family-reunification migration.`,
  NE: `The Nigerien (Niger) passport offers visa-free or visa-on-arrival entry to ~55 destinations primarily within ECOWAS (suspended after July 2023 coup), AU, plus several Caribbean + Pacific states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Nigerien diaspora in France ~25k, Côte d'Ivoire, Nigeria (cross-border Hausa-Fulani communities) supports family-reunification migration. Niger's January 2024 withdrawal from ECOWAS (with Mali + Burkina Faso) affects regional mobility arrangements pending new Sahel-states alliance frameworks.`,
  MZ: `The Mozambican passport offers visa-free or visa-on-arrival entry to ~60 destinations primarily within SADC (Southern African Development Community — 16 member states, varying mobility arrangements), AU, plus most of CPLP (Lusophone countries — Portugal, Brazil, Angola, Cape Verde, etc.). The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Mozambican diaspora in South Africa ~700k+ (the largest, via the bilateral mineworkers' agreement + free movement under SADC), Portugal ~80k, Brazil supports family-reunification migration.`,
  ZM: `The Zambian passport offers visa-free or visa-on-arrival entry to ~75 destinations primarily within SADC + COMESA + AU, plus several Caribbean + Asian states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. SADC Protocol on Facilitation of Movement of Persons (signed 2005, ratified by ~10 member states) provides streamlined regional mobility. Zambian diaspora in South Africa, the UK ~25k, the US, Australia supports family-reunification migration via Commonwealth ties + UK Skilled Worker (healthcare).`,
  NA: `The Namibian passport offers visa-free or visa-on-arrival entry to ~80 destinations primarily within SADC + AU, plus several Caribbean + Asian states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. SADC Protocol on Facilitation of Movement of Persons provides streamlined regional mobility. Substantial Namibian diaspora in South Africa, Germany ~10k (historical ties from German colonial era — particularly the Caprivi + Windhoek communities) supports family-reunification migration. Namibia hosts substantial German-Namibian community (~30k descendants of German colonial-era settlers).`,
  BW: `The Botswanan passport offers visa-free or visa-on-arrival entry to ~85 destinations primarily within SADC + AU, plus Hong Kong (90 days), Singapore, Russia, and the UK (6-month visa-free for Botswana via Commonwealth ties). The Schengen Area, US, Canada, Australia, Japan require embassy visas. Botswana is among Africa's most stable democracies — continuously held free elections since independence 1966. SADC Protocol on Facilitation of Movement of Persons supports streamlined regional mobility. Substantial South African residence + work flows for Botswanan professionals.`,
  RW: `The Rwandan passport offers visa-free or visa-on-arrival entry to ~75 destinations including most of Africa (EAC + COMESA + AU), Singapore (90 days), Hong Kong (90 days), and several Caribbean states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. EAC (East African Community — Kenya, Tanzania, Uganda, Rwanda, Burundi, South Sudan, DRC) provides streamlined regional mobility under a Common Market Protocol. Substantial Rwandan diaspora in Uganda, Burundi, the UK, Belgium (former colonial), Canada (Toronto, Calgary).`,
  ER: `The Eritrean passport offers visa-free or visa-on-arrival entry to ~35 destinations — one of the most travel-restricted documents globally. Primary visa-free / VOA access: select African states (AU + COMESA), Cuba, Bolivia. Most major destinations including the US, UK, Schengen, Canada, Australia, Japan require embassy visas. Eritrea's exit-visa requirement (separate from receiving-country visas) makes departure exceptionally difficult — most migration is irregular via Sudan / Ethiopia. Substantial Eritrean refugee diaspora in Sudan, Ethiopia, Israel, Germany, Sweden, the UK, the US, Canada supports asylum + family-reunification routes.`,
  SD: `The Sudanese passport offers visa-free or visa-on-arrival entry to ~40 destinations primarily within AU + Arab League + select Asian + Caribbean states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. The 2023+ civil war has dramatically restricted Sudanese mobility — many embassies have suspended visa services + scrutiny is heightened on Sudanese applications globally. Substantial Sudanese diaspora in Egypt ~4M+ (the largest, particularly Cairo + Khartoum-Cairo cross-border community), Saudi Arabia, UAE, the US, UK supports family-reunification + asylum routes.`,
  LY: `The Libyan passport offers visa-free or visa-on-arrival entry to ~40 destinations primarily within Arab League + AU + select Asian + Caribbean states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Libya's post-2011 political fragmentation has affected passport issuance + recognition — Libyan applications face heightened scrutiny globally. Substantial Libyan diaspora in Egypt, Tunisia, Italy, the UK supports family-reunification + asylum routes. UNHCR-mandated humanitarian programmes (Italy + Tunisia + Egypt) support refugee resettlement to EU member states.`,
  MG: `The Madagascan passport offers visa-free or visa-on-arrival entry to ~65 destinations primarily within AU + SADC + COMESA + IOC (Indian Ocean Commission — Mauritius, Comoros, Seychelles, Réunion), plus several Asian + Pacific states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Substantial Madagascan diaspora in France ~150k (the largest, particularly Île-de-France + Marseille), Réunion, Mauritius, Comoros supports family-reunification migration via colonial-era + Francophonie ties.`,
  MU: `The Mauritian passport offers visa-free or visa-on-arrival entry to ~145 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Hong Kong, Singapore, China (15 days mutual visa-free since 2019), and most of Africa. The US, Canada, Australia, Japan require embassy visas. Mauritius is among Africa's strongest passports — multilingual society (English, French, Creole) + dense Indian + Chinese + African heritage supports broad multilingual mobility. Substantial Mauritian diaspora in France, the UK ~30k, Australia, Canada.`,
  SC: `The Seychellois passport offers visa-free or visa-on-arrival entry to ~155 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Hong Kong, Singapore, China (30 days), Russia (30 days), and most of Africa. The US, Canada, Australia, Japan require embassy visas. Seychelles is among Africa's strongest passports per Henley Index. Substantial Seychellois diaspora in the UK, Australia, France ~10k supports family-reunification migration via Commonwealth + Francophonie ties.`,
  CV: `The Cape Verdean passport offers visa-free or visa-on-arrival entry to ~70 destinations primarily within ECOWAS, AU, CPLP (Lusophone countries — Portugal, Brazil, Angola, Mozambique, Guinea-Bissau, São Tomé, East Timor, Equatorial Guinea), plus several Caribbean + Latin American states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. The Cape Verde-EU Special Partnership (since 2007) supports deepened visa-facilitation arrangements. Substantial Cape Verdean diaspora in Portugal ~100k, the US (Boston / Providence), France, Senegal, Brazil supports family-reunification migration via CPLP.`,

  // ─── MIDDLE EAST — gaps ───
  YE: `The Yemeni passport offers visa-free or visa-on-arrival entry to ~30 destinations — among the most travel-restricted documents globally. Visa-free / VOA access: select Arab League states (varies by current political relations), Iran, several Caribbean + Pacific states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas + face heightened scrutiny since the 2014 civil war. Substantial Yemeni diaspora in Saudi Arabia ~1M+, Egypt, the US (Michigan especially — Dearborn), the UK, Indonesia supports family-reunification + asylum routes. UNHCR-mandated resettlement programmes prioritise vulnerable Yemenis.`,
  SY: `The Syrian passport offers visa-free or visa-on-arrival entry to ~30 destinations — among the most travel-restricted documents globally. Visa-free / VOA access: select Arab League states, Iran, Russia (visa-free 90 days), Venezuela, Bolivia. The Schengen Area, UK, US, Canada, Australia, Japan all require embassy visas + face heightened scrutiny since the 2011 civil war. Massive Syrian refugee diaspora in Türkiye ~3.6M (the largest), Lebanon, Jordan, Germany ~800k, Sweden, the Netherlands supports family-reunification + asylum routes via the UNHCR resettlement framework.`,
  PS: `The Palestinian Authority passport offers visa-free or visa-on-arrival entry to ~40 destinations primarily within the Arab League + AU + select Asian + Caribbean states. Recognition varies — ~140 UN states recognise Palestine; non-recognition by US, Israel, Canada, Australia, most of Western Europe affects bilateral visa arrangements. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas (some via Jordan-based consular services). Substantial Palestinian diaspora in Jordan ~2M+, Lebanon, Syria, Chile ~500k (the largest outside the Middle East), the US, UK, Canada supports family-reunification migration.`,
  AM: `The Armenian passport offers visa-free or visa-on-arrival entry to ~65 destinations including the Schengen Area (90/180, ETIAS from late 2026 — Armenia signed EU visa liberalisation in early 2024), most of the post-Soviet space (EAEU member — Russia, Belarus, Kazakhstan, Kyrgyzstan free movement), Iran (90 days, longstanding bilateral), China (visa-free 90 days since Jan 2024). The US, Canada, Australia, Japan, UK require embassy visas. Substantial Armenian diaspora in Russia ~2.5M+ (the largest), France ~600k, the US ~1.5M (LA especially — Glendale).`,

  // ─── ASIA — gaps ───
  MN: `The Mongolian passport offers visa-free or visa-on-arrival entry to ~75 destinations including Russia (30 days, longstanding bilateral), China (30 days for select purposes — varies), Türkiye (90 days), Singapore (30 days), Hong Kong, most of Latin America, and several CIS + Caribbean states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Substantial Mongolian diaspora in South Korea ~50k (the largest, via the EPS work permit), Russia, Germany, the US supports family-reunification migration. Inner Mongolia (China) hosts ~4M ethnic Mongols, supporting cross-border family ties.`,
  UZ: `The Uzbek passport offers visa-free or visa-on-arrival entry to ~60 destinations including most of the post-Soviet space (Russia, Belarus, Kazakhstan, Kyrgyzstan, Tajikistan visa-free; EAEU non-member but bilateral arrangements), Türkiye (30 days), Iran, Indonesia, Malaysia, plus several Caribbean + Latin American states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Substantial Uzbek diaspora in Russia ~5M+ (the largest, via the CIS labour mobility), Kazakhstan, Türkiye, South Korea (EPS), the US supports family-reunification migration.`,
  TJ: `The Tajik passport offers visa-free or visa-on-arrival entry to ~55 destinations including most of the post-Soviet space (CIS visa-free arrangements), Türkiye (30 days), Iran, Indonesia, plus several Caribbean + Latin American states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Substantial Tajik diaspora in Russia ~1.5M+ (the largest, via the CIS labour mobility), Kazakhstan, Kyrgyzstan supports family-reunification migration. Tajikistan is poorest of the Central Asian states — heavy remittance-dependent economy with substantial outward labour migration.`,
  KG: `The Kyrgyz passport offers visa-free or visa-on-arrival entry to ~70 destinations including most of the post-Soviet space (EAEU member — Russia, Belarus, Kazakhstan, Armenia free movement + labour-market access), Türkiye (30 days), South Korea (EPS), Indonesia, Malaysia, plus several Caribbean + Latin American states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Substantial Kyrgyz diaspora in Russia ~1M+ (the largest, via EAEU labour mobility), Kazakhstan, Türkiye supports family-reunification migration.`,
  TM: `The Turkmen passport offers visa-free or visa-on-arrival entry to ~50 destinations including Türkiye (30 days), Russia (under bilateral visa-required rules), most of CIS, plus several Caribbean + Latin American states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Turkmenistan's exceptional restrictiveness — exit visas not required formally but practical exit restrictions exist for many citizens. Substantial Turkmen diaspora in Türkiye (~80k+), Russia, Iran (cross-border Turkmen-Persian heritage). Turkmenistan-Iran-Türkiye triangle supports regional mobility.`,
  BT: `The Bhutanese passport offers visa-free or visa-on-arrival entry to ~55 destinations including India (free movement — open border, no passport required between India + Bhutan), Bangladesh (visa-on-arrival), Maldives, Indonesia, Thailand, Singapore (30 days), plus several Caribbean + Pacific states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Bhutan's traditional isolationism — most outward migration is to India (substantial Bhutanese-Indian community in Sikkim, West Bengal, Assam) + Australia + the US (Bhutanese-Nepali refugee resettlement programme delivered ~100k to the US 2008-2018).`,
  MO: `The Macanese (Macao SAR) passport offers visa-free or eTA-only entry to ~145 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Japan (90 days), South Korea (K-ETA), most of ASEAN + Latin America. The US requires a B1/B2 visa (Macao is NOT in the Visa Waiver Program — unlike Hong Kong holders, who similarly need a US visa). Macao has separate immigration controls from Mainland China — Macao residents enjoy visa-free access to Hong Kong (180 days) + Mainland China (Home Return Permit for ethnic-Chinese residents). Substantial Portuguese-Macanese community via colonial-era ties supports CPLP mobility.`,

  // ─── PACIFIC — gaps ───
  PG: `The Papua New Guinean passport offers visa-free or visa-on-arrival entry to ~45 destinations primarily within the Pacific Islands Forum + select Asian + Caribbean states. The Schengen Area, UK, US, Canada, Australia (visa required despite proximity), Japan require embassy visas. The Pacific Australia Labour Mobility (PALM) scheme provides employer-sponsored work in Australia for PNG nationals — substantial seasonal-worker pipeline particularly in horticulture + meat processing. Substantial PNG diaspora in Australia, the Solomon Islands (cross-border Bougainville arrangements), New Zealand supports family-reunification migration.`,
  FJ: `The Fijian passport offers visa-free or visa-on-arrival entry to ~90 destinations including the Schengen Area (90/180, ETIAS from late 2026 — Fiji signed Schengen visa liberalisation in 2020), the UK (6 months visa-free), Russia (90 days, longstanding bilateral), most of the Pacific + Asia + Caribbean. The US, Canada, Australia, Japan require embassy visas. Substantial Fijian diaspora in Australia ~80k, New Zealand ~25k, the US, Canada, the UK supports family-reunification migration via the Pacific Access Category (PAC) lottery to New Zealand + Pacific Engagement Visa (PEV) lottery to Australia (launched 2024).`,
  WS: `The Samoan passport offers visa-free or visa-on-arrival entry to ~135 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Russia (90 days), most of the Pacific + Asia + Caribbean. The US, Canada, Australia, Japan require embassy visas. Substantial Samoan diaspora in New Zealand ~180k (the largest, via the Samoan Quota Scheme — 1,100 spots/year), Australia ~120k, American Samoa (US territory) ~50k, the US (California especially) supports family-reunification migration.`,
  TO: `The Tongan passport offers visa-free or visa-on-arrival entry to ~115 destinations including the Schengen Area (90/180, ETIAS from late 2026), the UK (6 months visa-free), Russia (90 days), most of the Pacific + Asia + Caribbean. The US, Canada, Australia, Japan require embassy visas. Substantial Tongan diaspora in New Zealand ~80k (the largest, via the Pacific Access Category lottery — 250 spots/year), Australia ~30k, the US (Utah especially via LDS Church connections) supports family-reunification migration via PAC + PEV lotteries.`,
  VU: `The Vanuatu passport offers visa-free or visa-on-arrival entry to ~125 destinations including the Schengen Area (suspension under review since 2022 due to CBI concerns — currently visa required), the UK (visa-free suspended 2023 also CBI-related), Russia, most of the Pacific + Asia + Caribbean. The US, Canada, Australia, Japan require embassy visas. Vanuatu runs the Pacific's only active Citizenship by Investment Program — USD 130k+ contribution route — which has caused EU + UK to suspend visa-free arrangements due to due-diligence concerns. CBI passport-holders face heightened scrutiny.`,
  SB: `The Solomon Islander passport offers visa-free or visa-on-arrival entry to ~40 destinations primarily within the Pacific Islands Forum + select Asian + Caribbean states. The Schengen Area, UK, US, Canada, Australia, Japan require embassy visas. Substantial Solomon Islander diaspora in Australia (via PALM scheme), New Zealand (via PAC + PEV), Fiji (regional labour migration), Papua New Guinea (cross-border Bougainville arrangements) supports family-reunification migration. Pacific Australia Labour Mobility (PALM) scheme provides employer-sponsored work in Australia.`,
};

export function passportIntroFor(iso2: string): string | undefined {
  return PASSPORT_INTROS[iso2.toUpperCase()];
}
